import{_ as o,c as a,a1 as t,o as r}from"./chunks/framework.BDxlaA_J.js";const w=JSON.parse('{"title":"Windows Scanning Tools","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/2-scanning-networks/6-WindowsTools.md","filePath":"categories/ethical-hacking-labs/2-scanning-networks/6-WindowsTools.md"}'),n={name:"categories/ethical-hacking-labs/2-scanning-networks/6-WindowsTools.md"};function s(i,e,l,c,d,h){return r(),a("div",null,e[0]||(e[0]=[t('<h1 id="windows-scanning-tools" tabindex="-1">Windows Scanning Tools <a class="header-anchor" href="#windows-scanning-tools" aria-label="Permalink to &quot;Windows Scanning Tools&quot;">​</a></h1><h2 id="colasoft-packet-builder" tabindex="-1">Colasoft Packet Builder <a class="header-anchor" href="#colasoft-packet-builder" aria-label="Permalink to &quot;Colasoft Packet Builder&quot;">​</a></h2><p>Colasoft Packet Builder enables creating custom network packets; users can use this tool to check their network protection against attacks and intruders. Colasoft Packet Builder includes a very powerful editing feature. Besides common HEX editing raw data, it features a Decoding Editor allowing users to edit specific protocol field values much easier.</p><p>Users are also able to edit decoding information in two editors - Decode Editor and Hex Editor. Users can select one from the provided templates Ethernet Packet, ARP Packet, IP Packet, TCP Packet and UDP Packet, and change the parameters in the decoder editor, hexadecimal editor or ASCII editor to create packets. Any changes will be immediately displayed in the other two windows. In addition to building packets,Colasoft Packet Builder also supports saving packets to packet files and sending packets to network. [Free/Paid] <a href="https://www.colasoft.com/packet_builder/" target="_blank" rel="noreferrer">https://www.colasoft.com/packet_builder/</a></p><h2 id="netscantools-pro" tabindex="-1">NetScanTools Pro <a class="header-anchor" href="#netscantools-pro" aria-label="Permalink to &quot;NetScanTools Pro&quot;">​</a></h2><p>NetScanTools Pro is an integrated collection of internet information gathering and network troubleshooting utilities for Network Professionals. Research IPv4 addresses, IPv6 addresses, hostnames, domain names, email addresses and URLs automatically** or with manual tools. It is designed for the Windows operating system. [Trial/Paid] <a href="https://www.netscantools.com/" target="_blank" rel="noreferrer">https://www.netscantools.com/</a></p><h2 id="ip-tools" tabindex="-1">IP-Tools <a class="header-anchor" href="#ip-tools" aria-label="Permalink to &quot;IP-Tools&quot;">​</a></h2><p>IP-Tools consist of multiple individual tools, ranging from basic bandwidth monitoring to spoofing and decoding. You can scan for live hosts, ping scan, simple port scan, whois and so on. [Trial/Paid] <a href="https://ip-tools.en.softonic.com/" target="_blank" rel="noreferrer">https://ip-tools.en.softonic.com/</a></p><h2 id="angry-ip-scanner" tabindex="-1">Angry IP Scanner <a class="header-anchor" href="#angry-ip-scanner" aria-label="Permalink to &quot;Angry IP Scanner&quot;">​</a></h2><p>Angry IP Scanner is an open-source and cross-platform network scanner designed to scan IP addresses and ports. [Free software] <a href="https://angryip.org/" target="_blank" rel="noreferrer">https://angryip.org/</a></p><h1 id="windows-proxy-tools" tabindex="-1">Windows Proxy Tools <a class="header-anchor" href="#windows-proxy-tools" aria-label="Permalink to &quot;Windows Proxy Tools&quot;">​</a></h1><h2 id="proxy-workbench" tabindex="-1">Proxy Workbench <a class="header-anchor" href="#proxy-workbench" aria-label="Permalink to &quot;Proxy Workbench&quot;">​</a></h2><p>Proxy Workbench is a unique proxy server - ideal for developers, security experts, and trainers - that displays data in real time.</p><p>Daisy Chaining of Proxies can make traffic analysis far more complex and most difficult for an eavesdropper to be able to monitor different parts of the Internet. [Free] <a href="https://en.freedownloadmanager.org/Windows-PC/Proxy-Workbench.html" target="_blank" rel="noreferrer">https://en.freedownloadmanager.org/Windows-PC/Proxy-Workbench.html</a></p><h2 id="proxy-switcher" tabindex="-1">Proxy Switcher <a class="header-anchor" href="#proxy-switcher" aria-label="Permalink to &quot;Proxy Switcher&quot;">​</a></h2><p>Proxy Switcher allows you to automatically execute actions according to the detected network connection. Proxy Switcher is for all the anonymous browsing needs. It can be used to avoid all sorts of limitations imposed by various sites. Be that a download site that limits amount of downloads. Or video site works only in a particular country - more often than not it gets defeated by the anonymous browsing features Proxy Switcher provides. [Trial/Paid] <a href="https://www.proxyswitcher.com/" target="_blank" rel="noreferrer">https://www.proxyswitcher.com/</a></p><h1 id="vpn-s" tabindex="-1">VPN&#39;s <a class="header-anchor" href="#vpn-s" aria-label="Permalink to &quot;VPN&#39;s&quot;">​</a></h1><h2 id="cyberghost-vpn" tabindex="-1">CyberGhost VPN <a class="header-anchor" href="#cyberghost-vpn" aria-label="Permalink to &quot;CyberGhost VPN&quot;">​</a></h2><p>VPN software that allows you to surf anonymously, access blocked or censored content. [Paid] <a href="https://www.cyberghostvpn.com/" target="_blank" rel="noreferrer">https://www.cyberghostvpn.com/</a></p><h2 id="proton-vpn" tabindex="-1">Proton VPN <a class="header-anchor" href="#proton-vpn" aria-label="Permalink to &quot;Proton VPN&quot;">​</a></h2><p>VPN software that allows you to surf anonymously, access blocked or censored content. [Paid] <a href="https://protonvpn.com/" target="_blank" rel="noreferrer">https://protonvpn.com/</a></p><h1 id="network-discovery-tool" tabindex="-1">Network Discovery Tool <a class="header-anchor" href="#network-discovery-tool" aria-label="Permalink to &quot;Network Discovery Tool&quot;">​</a></h1><h2 id="network-topology-mapper" tabindex="-1">Network Topology Mapper <a class="header-anchor" href="#network-topology-mapper" aria-label="Permalink to &quot;Network Topology Mapper&quot;">​</a></h2><p>SolarWinds Network Topology Mapper automatically discovers your network and produces a comprehensive network diagram that can be easily exported to MS Office. Network Topology Mapper automatically detects new devices and changes to network topology. it simplifies inventory management for hardware and software assets, addresses reporting needs for PCI compliance and other regulatory requirements. [Trial/Paid] <a href="https://www.solarwinds.com/network-topology-mapper" target="_blank" rel="noreferrer">https://www.solarwinds.com/network-topology-mapper</a></p>',24)]))}const f=o(n,[["render",s]]);export{w as __pageData,f as default};
